### The Deobfuscated Code

Here is the clean, human-readable version of exactly what the obfuscated code is executing under the hood:

```javascript
// --- 1. Math & Physics Constants ---
const TWO_PI = 6.283;
const PHI = 1.618;
const SQRT_HALF = 0.707;

const config = {
    repulsionForce: 4000,
    springTension: 0.004,
    friction: 0.92,
    centerAttractance: 0.0003,
    maxParticles: 40,
    particleAttenuation: 0.04,
    cameraPhase: 0.06
};

// --- 2. Graph Data (Nodes and Springs) ---
const nodes = [
    { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const links = [
    { a: 'hub',     b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub',     b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub',     b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub',     b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub',     b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha',   b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma',   b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha',   b: 'epsilon', rest: 200, k: 0.002 }
];

// --- 3. Camera & State ---
let currentView = { x: 400, y: 300, scale: 1 };
let targetView  = { x: 400, y: 300, scale: 1 };
let particles = [];
let tick = 0;

// Helper function to find a node by its ID
function getNodeById(id) {
    return nodes.find(node => node.id === id);
}

// --- 4. Main Physics Update ---
function updatePhysics() {
    // A. N-Body Repulsion (Nodes push each other away)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let distSq = (dx * dx + dy * dy) || 1;
            let force = config.repulsionForce / distSq;

            let dist = Math.sqrt(distSq) || 1;
            let fx = (dx / dist) * force;
            let fy = (dy / dist) * force;

            nodes[i].vx += fx; nodes[i].vy += fy;
            nodes[j].vx -= fx; nodes[j].vy -= fy;
        }
    }

    // B. Spring Forces (Links pull nodes together)
    for (let link of links) {
        let nodeA = getNodeById(link.a);
        let nodeB = getNodeById(link.b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let dist = Math.sqrt(dx * dx + dy * dy) || 1;

        let stretch = dist - link.rest;
        let force = (link.k || config.springTension) * stretch;

        nodeA.vx += (dx / dist) * force; nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force; nodeB.vy -= (dy / dist) * force;
    }

    // C. Apply Friction, Center Gravity, and Velocity
    for (let node of nodes) {
        node.vx += (400 - node.x) * config.centerAttractance;
        node.vy += (300 - node.y) * config.centerAttractance;

        node.vx *= config.friction;
        node.vy *= config.friction;

        node.x += node.vx;
        node.y += node.vy;
    }
}

// --- 5. Particle System ---
function emitParticle() {
    if (particles.length >= config.maxParticles) return;

    // Pick a random node to spawn a particle from
    let sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * TWO_PI;
    let speed = 0.3 + (Math.random() * SQRT_HALF);

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + (Math.random() * 1200),
        size: Math.max(0.8, Math.random() * PHI)
    });
}

function updateParticles() {
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];

        // Particles slow down slightly over time
        p.vx *= (1 - (config.particleAttenuation * 0.125));
        p.vy *= (1 - (config.particleAttenuation * 0.125));

        p.x += p.vx;
        p.y += p.vy;
        p.age++;

        if (p.age > p.maxAge) {
            particles.splice(i, 1);
        }
    }
}

// --- 6. Camera Interpolation ---
function updateCamera() {
    currentView.x += (targetView.x - currentView.x) * config.cameraPhase;
    currentView.y += (targetView.y - currentView.y) * config.cameraPhase;
    currentView.scale += (targetView.scale - currentView.scale) * config.cameraPhase;
}

// --- 7. Main Game Loop ---
function loop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    // Spawn a particle every 3rd frame
    if (tick % 3 === 0) {
        emitParticle();
    }
    tick++;
}

// Run at ~60 FPS
setInterval(loop, 16);
```

*(Note: The provided obfuscated code doesn't actually draw anything to a `<canvas>`. It strictly handles the math and logic in the background. It is highly likely there is another chunk of code on the webpage that reads the `nodes` and `particles` arrays to draw shapes onto an HTML5 canvas.)*
